parameters.jsCode:
const payload = $('Get File Payload').item.json;

const allowedCategories = new Set([
  'Перші страви',
  'Другі страви',
  'Десерти',
  'Закуски',
  'Салати',
  'Випічка',
  'Напої',
  'Консервація',
  'Інше'
]);

function cleanText(value, fallback = 'recipe') {
  let text = String(value || fallback).normalize('NFKC');
  text = text.replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}]/gu, '');
  text = text.replace(/[<>:"/\\|?*\x00-\x1f]/g, ' ');
  text = text.replace(/[’'`]/g, '');
  text = text.replace(/\.+/g, ' ');
  text = text.replace(/[^\p{L}\p{N}\s()_-]/gu, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || fallback;
}

function clamp(value, maxLength = 70) {
  const text = cleanText(value);
  return text.length > maxLength ? text.slice(0, maxLength).trim() : text;
}

function normalizeFolder(folder) {
  return '/' + String(folder || '/Documents/Recipe')
    .split('/')
    .map((part) => cleanText(part, ''))
    .filter(Boolean)
    .join('/');
}

const category = allowedCategories.has(String(payload.category || '').trim())
  ? String(payload.category).trim()
  : 'Інше';
const recipeId = payload.recipe_id || payload.id || '';
const title = clamp(payload.title || payload.filename || 'recipe');
const baseName = recipeId ? `${recipeId} - ${title}` : title;
const nextcloudRoot = normalizeFolder(payload.nextcloud_root_folder || '/Documents/Recipe');
const nextcloudFolder = `${nextcloudRoot}/${category}`;
const remoteDocxPath = `${nextcloudFolder}/${baseName}.docx`;
const remotePdfPath = `${nextcloudFolder}/${baseName}.pdf`;

return [{
  json: {
    ...payload,
    category,
    normalized_title: title,
    nextcloud_root_folder: nextcloudRoot,
    nextcloud_folder: nextcloudFolder,
    remote_docx_path: remoteDocxPath,
    remote_pdf_path: remotePdfPath,
    docx_filename: `${baseName}.docx`,
    pdf_filename: `${baseName}.pdf`
  }
}];

const payload = $('Normalize Nextcloud Paths').item.json;

return [{
  json: {
    recipe_id: payload.recipe_id,
    video_id: payload.video_id,
    title: payload.title,
    category: payload.category,
    docx_path: payload.docx_path,
    pdf_path: payload.pdf_path,
    remote_path: payload.remote_docx_path,
    filename: payload.docx_filename,
    file_kind: 'docx'
  },
  binary: {
    data: {
      data: payload.docx_base64,
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      fileName: payload.docx_filename,
      fileExtension: 'docx'
    }
  }
}];

const payload = $('Normalize Nextcloud Paths').item.json;

return [{
  json: {
    recipe_id: payload.recipe_id,
    video_id: payload.video_id,
    title: payload.title,
    category: payload.category,
    docx_path: payload.docx_path,
    pdf_path: payload.pdf_path,
    remote_path: payload.remote_pdf_path,
    filename: payload.pdf_filename,
    file_kind: 'pdf'
  },
  binary: {
    data: {
      data: payload.pdf_base64,
      mimeType: 'application/pdf',
      fileName: payload.pdf_filename,
      fileExtension: 'pdf'
    }
  }
}];

const payload = $('Normalize Nextcloud Paths').item.json;
const docx = $('Share DOCX').item.json;
const pdf = $('Share PDF').item.json;

function sqlQuote(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function intOrNull(value) {
  const parsed = Number.parseInt(value, 10);
  return Number.isFinite(parsed) ? String(parsed) : 'NULL';
}

const docxUrl = docx.url || docx.link || '';
const pdfUrl = pdf.url || pdf.link || '';
const recipeIdSql = intOrNull(payload.recipe_id);
const videoIdSql = sqlQuote(payload.video_id);

const updateSql = `WITH updated_recipe AS (
  UPDATE recipes
  SET nextcloud_docx_url = ${sqlQuote(docxUrl)},
      nextcloud_pdf_url = ${sqlQuote(pdfUrl)},
      processed = TRUE,
      updated_at = NOW()
  WHERE (${recipeIdSql} IS NOT NULL AND id = ${recipeIdSql})
     OR (${videoIdSql} IS NOT NULL AND video_id = ${videoIdSql})
  RETURNING id, video_id, title, nextcloud_docx_url, nextcloud_pdf_url
), updated_log AS (
  UPDATE video_log
  SET processed = TRUE,
      status = 'completed',
      error_details = NULL,
      updated_at = NOW()
  WHERE video_id = (SELECT video_id FROM updated_recipe LIMIT 1)
  RETURNING video_id
)
SELECT * FROM updated_recipe;`;

return [{
  json: {
    recipe_id: payload.recipe_id,
    video_id: payload.video_id,
    title: payload.title,
    category: payload.category,
    docx_path: payload.docx_path,
    pdf_path: payload.pdf_path,
    nextcloud_folder: payload.nextcloud_folder,
    remote_docx_path: payload.remote_docx_path,
    remote_pdf_path: payload.remote_pdf_path,
    nextcloud_docx_url: docxUrl,
    nextcloud_pdf_url: pdfUrl,
    update_sql: updateSql
  }
}];
